const profiles = [];

for (const item of $input.all()) {
  let val = item.json;

  // Step 1 â n8n pagination wraps the full API response as a string in item.json.data
  if (val && typeof val.data === 'string') {
    try { val = JSON.parse(val.data); } catch (e) { val = null; }
  }

  // Step 2 â parsed result is { data: [...profiles], links: {...} }; extract the array
  if (val && !Array.isArray(val) && Array.isArray(val.data)) {
    val = val.data;
  }

  // Step 3 â val is now the profiles array (or a single profile object)
  if (Array.isArray(val)) {
    for (const profile of val) {
      profiles.push({ json: profile });
    }
  } else if (val && val.id) {
    profiles.push({ json: val });
  }
}

return profiles;

const now = DateTime.now();

// Generate a stable run_id from the execution start time.
// Using DateTime avoids $execution.id which is not available in all n8n versions.
const runId = now.toFormat('yyyyMMdd-HHmmss') + '-' + Math.random().toString(36).slice(2, 8);

return $input.all().map(item => {
  const profile = item.json;
  const attrs = profile.attributes || {};

  const candidates = [attrs.last_event_date, attrs.created].filter(Boolean);
  const lastEngaged = candidates.length > 0
    ? candidates.map(d => DateTime.fromISO(d)).reduce((a, b) => (a > b ? a : b))
    : null;

  const daysSince = lastEngaged
    ? Math.floor(now.diff(lastEngaged, 'days').days)
    : 999;

  let tier, engagement_score, action_taken;
  if (daysSince < 30) {
    tier = 'active';         engagement_score = 100; action_taken = 'none';
  } else if (daysSince < 60) {
    tier = 'moderate_decay'; engagement_score = 60;  action_taken = 'log';
  } else if (daysSince < 90) {
    tier = 'high_decay';     engagement_score = 25;  action_taken = 'log';
  } else {
    tier = 'critical';       engagement_score = 0;   action_taken = 'suppress';
  }

  return {
    json: {
      profile_id:       profile.id,
      email:            attrs.email,
      days_since_active: daysSince,
      tier,
      engagement_score,
      action_taken,
      run_id: runId
    }
  };
});

const items = $input.all();
let active = 0, moderate = 0, high = 0, critical = 0;

for (const item of items) {
  const tier = item.json.tier;
  if (tier === 'active')              active++;
  else if (tier === 'moderate_decay') moderate++;
  else if (tier === 'high_decay')     high++;
  else if (tier === 'critical')       critical++;
}

// run_id flows through from Score Profiles via item data â no cross-node reference needed
const runId    = items[0]?.json?.run_id || DateTime.now().toFormat('yyyyMMdd-HHmmss');
const runStart = DateTime.now().toISO();

return [{
  json: {
    run_id:           runId,
    run_start:        runStart,
    run_end:          DateTime.now().toISO(),
    total_profiles:   items.length,
    active_count:     active,
    moderate_count:   moderate,
    high_count:       high,
    critical_count:   critical,
    suppressed_count: critical,
    status:           'success'
  }
}];

const d = $input.first().json;
const date = DateTime.now().toFormat('MMMM dd, yyyy');

const row = (label, count, action, color) =>
  `
  <tr>
    <td style="padding:14px 16px;font-size:14px;color:#333;">${label}</td>
    <td align="right" style="padding:14px 16px;font-size:14px;font-weight:600;color:#111;">
      ${count}
    </td>
    <td style="padding:14px 16px;font-size:13px;">
      <span style="
        padding:6px 10px;
        border-radius:6px;
        background:${color.bg};
        color:${color.text};
        font-weight:500;
      ">
        ${action}
      </span>
    </td>
  </tr>
`;

const html = `
<div style="background:#f4f6f8;padding:40px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">

  <div style="max-width:600px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 8px 24px rgba(0,0,0,0.06);">

    <!-- Header -->
    <div style="padding:24px 28px;background:linear-gradient(135deg,#4f46e5,#7c3aed);color:#fff;">
      <h2 style="margin:0;font-size:20px;font-weight:600;">
        ð Klaviyo Decay Report
      </h2>
      <p style="margin:6px 0 0;font-size:13px;opacity:0.9;">
        ${date}
      </p>
    </div>

    <!-- Summary -->
    <div style="padding:20px 28px;border-bottom:1px solid #eee;">
      <p style="margin:0;font-size:14px;color:#555;">
        Hereâs your latest engagement decay breakdown. Critical profiles have been automatically suppressed to maintain deliverability.
      </p>
    </div>

    <!-- Table -->
    <table style="width:100%;border-collapse:collapse;">
      <thead>
        <tr style="background:#fafafa;text-transform:uppercase;font-size:11px;color:#888;letter-spacing:0.05em;">
          <th align="left" style="padding:12px 16px;">Tier</th>
          <th align="right" style="padding:12px 16px;">Profiles</th>
          <th align="left" style="padding:12px 16px;">Status</th>
        </tr>
      </thead>
      <tbody>
        ${row('Active (<30 days)', d.active_count, 'Healthy', {
          bg:'#ecfdf5', text:'#059669'
        })}

        ${row('Moderate Decay (30â60 days)', d.moderate_count, 'Monitor', {
          bg:'#fffbeb', text:'#d97706'
        })}

        ${row('High Decay (60â90 days)', d.high_count, 'At Risk', {
          bg:'#fff7ed', text:'#ea580c'
        })}

        ${row('<strong>Critical (90+ days)</strong>', `<strong>${d.critical_count}</strong>`, 'Suppressed', {
          bg:'#fef2f2', text:'#dc2626'
        })}

        <tr style="border-top:2px solid #eee;background:#fafafa;">
          <td style="padding:14px 16px;font-weight:600;">Total</td>
          <td align="right" style="padding:14px 16px;font-weight:700;">
            ${d.total_profiles}
          </td>
          <td></td>
        </tr>
      </tbody>
    </table>

    <!-- Footer -->
    <div style="padding:20px 28px;font-size:12px;color:#777;border-top:1px solid #eee;">
      <p style="margin:0 0 8px;">
        <strong>Run ID:</strong> ${d.run_id}
      </p>
      <p style="margin:0 0 8px;">
        <strong>Started:</strong> ${d.run_start}
      </p>
      <p style="margin:0;">
        <strong>Completed:</strong> ${d.run_end}
      </p>
    </div>

  </div>

  <!-- Bottom note -->
  <div style="max-width:600px;margin:12px auto 0;text-align:center;font-size:11px;color:#aaa;">
    Automated report â¢ Deliverability Protection System
  </div>

</div>
`;

return [{
  json: {
    html_report: html,
    email_subject: `ð Klaviyo Decay Report â ${date} | ${d.critical_count} suppressed`
  }
}];

const criticalProfiles = $input.all();
if (criticalProfiles.length === 0) {
  return [{ json: { profiles_suppressed: 0, status: 'no_critical_profiles' } }];
}

const batchSize = 100;
const apiKey = $env.KLAVIYO_API_KEY;
const results = [];
let totalSuppressed = 0;

for (let i = 0; i < criticalProfiles.length; i += batchSize) {
  const batch = criticalProfiles.slice(i, i + batchSize);
  const profilesData = batch.map(p => ({
    type: 'profile',
    attributes: { email: p.json.email }
  }));

  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: 'https://a.klaviyo.com/api/profile-suppression-bulk-create-jobs/',
      headers: {
        'Authorization': 'Klaviyo-API-Key ' + apiKey,
        'revision': '2024-10-15',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        data: {
          type: 'profile-suppression-bulk-create-job',
          attributes: { profiles: { data: profilesData } }
        }
      })
    });
    totalSuppressed += batch.length;
  } catch (error) {
    results.push({
      json: { batch: Math.floor(i / batchSize) + 1, error: error.message, status: 'error' }
    });
  }
}

return results.length === 0
  ? [{ json: { profiles_suppressed: totalSuppressed, status: 'success' } }]
  : results;

const err  = $json.execution?.error || {};
const init = (() => { try { return $('Set: Initialize Run').first().json; } catch(e) { return {}; } })();

return [{
  json: {
    run_id:           init.run_id || ('err-' + DateTime.now().toMillis()),
    run_start:        init.run_start || null,
    run_end:          DateTime.now().toISO(),
    total_profiles:   0,
    active_count:     0,
    moderate_count:   0,
    high_count:       0,
    critical_count:   0,
    suppressed_count: 0,
    status:           'failed',
    error_message:    err.message || $json.error || 'Unknown error'
  }
}];
